B.HH=new A.qe(null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null)
B.HI=new A.x2(null,null,null,null,null,null,null,null,null)
B.HJ=new A.aY(8,8)
B.HK=new A.aY(1.5,1.5)
B.HL=new A.a3(0,!0)
B.HM=new A.a3("Field tour in watershed","Gira de campo en la cuenca hidrogr\xe1fica")
B.HN=new A.a3("Stage One: Co-design","Define mapping goals collaboratively with community leadership.")
B.wM=new A.yy(2,"collapsed")
B.HO=new A.a3(B.wM,B.wM)
B.HP=new A.a3("Community member portrait","Retrato de miembro de la comunidad")
B.HQ=new A.a3("\xbfCu\xe1nto tiempo tomar\xe1 el proyecto?","El proyecto est\xe1 dise\xf1ado en tres fases, dependiendo de la financiaci\xf3n:\n\nA\xf1o 1: Mapeo participativo y desarrollo de base de datos geoespacial.\n\nA\xf1o 2: Zonificaci\xf3n impulsada por consenso y desarrollo de directrices de uso del suelo comunitario.\n\nA\xf1o 3: Producci\xf3n final del mapa, s\xedntesis e integraci\xf3n en marcos de planificaci\xf3n de manejo.\n\nEste enfoque graduado prioriza la minuciosidad e impacto a largo plazo sobre la velocidad.")
B.HR=new A.a3("Stage Two: Training","Equip local researchers with GPS, mapping, and documentation tools.")
B.HS=new A.a3("Etapa Cuatro: Producci\xf3n SIG","Digitalizar y estandarizar los resultados para uso de planificaci\xf3n y gobernanza.")
B.HT=new A.a3("How will donated funds be used?","Donated funds directly support field-based research and community collaboration. Primary expenditures include workshops, equipment (GPS, drones, starlink), local geographer compensation, and researcher travel.\n\nAdministrative costs are minimized through institutional partnership with the University of Kansas. The project prioritizes directing resources toward community engagement and conservation outcomes.")
B.HU=new A.a3("Rainforest lizard","Lagarto de la selva tropical")
B.HV=new A.a3("Etapa Uno: Codise\xf1o","Definir objetivos de mapeo colaborativamente con el liderazgo comunitario.")
B.HW=new A.a3("\xbfQui\xe9n autoriza este proyecto?","Esta iniciativa procede solo con consentimiento comunitario y coordinaci\xf3n institucional. Durante una expedici\xf3n de reconocimiento en verano de 2025, el equipo de investigaci\xf3n se reuni\xf3 con la comunidad ind\xedgena de San Juan Peque\xf1\xed, particip\xf3 en un Congreso Local formal y recibi\xf3 aprobaci\xf3n escrita.\n\nEsta autorizaci\xf3n se alinea con la Ley 72 de 2008 de Panam\xe1 que rige las Tierras Colectivas Ind\xedgenas. El proyecto contin\xfaa solo a trav\xe9s de acuerdo colaborativo con el liderazgo comunitario.")
B.HX=new A.a3("\xbfC\xf3mo ayuda el mapeo a proteger un \xe1rea?","Los l\xedmites del parque nacional por s\xed solos no garantizan la protecci\xf3n. El manejo efectivo requiere comprender los procesos ecol\xf3gicos y sociales que ocurren dentro de esos l\xedmites.\n\nEl mapeo participativo de investigaci\xf3n traduce el conocimiento geogr\xe1fico ind\xedgena a formatos estructurados que pueden apoyar la zonificaci\xf3n, el monitoreo y la planificaci\xf3n de gobernanza a largo plazo. En un nivel fundamental, es dif\xedcil proteger lo que no se entiende claramente.")
B.HY=new A.a3("Will the data be publicly available?","Final outputs will be shared publicly. Sensitive knowledge remains under community control in accordance with data sovereignty principles.")
B.HZ=new A.a3("Rainforest monkey","Mono de la selva tropical")
B.I_=new A.a3("Why does the health of Chagres National Park matter for people in the United States?","Chagres National Park provides approximately 40 percent of the freshwater used in Panama Canal operations and roughly 80 percent of the drinking water for Panama City. The Canal remains one of the most strategically important global trade corridors, moving a significant portion of U.S.-bound maritime commerce.\n\nRecent droughts have demonstrated that water scarcity is the Canal's greatest operational vulnerability. Long-term watershed health directly affects trade reliability, regional diplomatic stability, and economic security.")
B.I0=new A.a3("\xbfC\xf3mo se compensan a los miembros de la comunidad?","Los miembros de la comunidad se capacitan como ge\xf3grafos locales en recopilaci\xf3n de datos GPS y t\xe9cnicas de mapeo. Los participantes reciben compensaci\xf3n por su tiempo y experiencia.")
B.I1=new A.a3("Stage Three: Field Verification","Collect ground-truth points through shared site visits.")
B.I2=new A.a3("River lancha transport","Transporte en lancha por el r\xedo")
B.I3=new A.a3("How long will the project take?","The project is designed in three phases, depending on funding:\n\nYear 1: Participatory mapping and geospatial database development.\n\nYear 2: Consensus-driven zoning and development of community land-use guidelines.\n\nYear 3: Final map production, synthesis, and integration into management planning frameworks.\n\nThis phased approach prioritizes thoroughness and long-term impact over speed.")
B.I4=new A.a3("Can this model be replicated elsewhere?","Yes. The framework combines participatory GIS, zoning, and institutional collaboration in a structured format designed to be adaptable to other protected areas.")
B.I5=new A.a3("\xbfSe puede replicar este modelo en otros lugares?","S\xed. El marco combina SIG participativo, zonificaci\xf3n y colaboraci\xf3n institucional en un formato estructurado dise\xf1ado para ser adaptable a otras \xe1reas protegidas.")
B.I6=new A.a3("\xbfPor qu\xe9 importa la salud del Parque Nacional Chagres?","El Parque Nacional Chagres proporciona aproximadamente el 40 por ciento del agua dulce utilizada en las operaciones del Canal de Panam\xe1 y aproximadamente el 80 por ciento del agua potable para la Ciudad de Panam\xe1. El Canal sigue siendo uno de los corredores comerciales globales m\xe1s estrat\xe9gicamente importantes.\n\nLas sequ\xedas recientes han demostrado que la escasez de agua es la mayor vulnerabilidad operativa del Canal. La salud de la cuenca a largo plazo afecta directamente la confiabilidad del comercio, la estabilidad diplom\xe1tica regional y la seguridad econ\xf3mica.")
B.I7=new A.a3("Etapa Dos: Capacitaci\xf3n","Capacitar a investigadores locales con herramientas de GPS, mapeo y documentaci\xf3n.")
B.I8=new A.a3("\xbfEstar\xe1n los datos disponibles p\xfablicamente?","Los resultados finales se compartir\xe1n p\xfablicamente. El conocimiento sensible permanece bajo control comunitario de acuerdo con los principios de soberan\xeda de datos.")
B.I9=new A.a3("Etapa Tres: Verificaci\xf3n de Campo","Recopilar puntos de verdad a trav\xe9s de visitas compartidas al sitio.")
B.Ia=new A.a3("Stage Four: GIS Production","Digitize and standardize outputs for planning and governance use.")
B.Ib=new A.a3("\xbfNo ha sido mapeado ya todo el mundo?","No. Hay una diferencia entre las im\xe1genes satelitales de un \xe1rea desde sat\xe9lites y los tipos de mapas que estamos haciendo. El nivel de detalle que combina geograf\xeda f\xedsica con informaci\xf3n cultural-hist\xf3rica en la comunidad es \xfanico y cr\xedtico para nuestro proceso.")
B.Ic=new A.a3("How are community members involved and compensated?","Community members are trained as local geographers in GPS data collection and mapping techniques. Participants are compensated for their time and expertise.")
B.Id=new A.a3("Is this project political?","The project is non-partisan and research-driven. Its focus is watershed stewardship, participatory governance, and environmental monitoring.")
B.wK=new A.yy(0,"left")
B.wL=new A.yy(1,"right")
B.Ie=new A.a3(B.wK,B.wL)
B.fw=new A.c3(4,"scrollLeft")
B.fx=new A.c3(8,"scrollRight")
B.If=new A.a3(B.fw,B.fx)
B.Ig=new A.a3("\xbfC\xf3mo se usar\xe1n los fondos donados?","Los fondos donados apoyan directamente la investigaci\xf3n de campo y la colaboraci\xf3n comunitaria. Los gastos principales incluyen talleres, equipos (GPS, drones, starlink), compensaci\xf3n de ge\xf3grafos locales y viajes de investigadores.\n\nLos costos administrativos se minimizan a trav\xe9s de asociaci\xf3n institucional con la Universidad de Kansas. El proyecto prioriza dirigir recursos hacia el compromiso comunitario y resultados de conservaci\xf3n.")
B.Ih=new A.a3("\xbfEs este proyecto pol\xedtico?","El proyecto es apartidista e impulsado por la investigaci\xf3n. Su enfoque es el manejo de cuencas hidrogr\xe1ficas, gobernanza participativa y monitoreo ambiental.")
B.Ii=new A.a3(B.fx,B.fw)
B.Ij=new A.a3(!1,!1)
B.Ik=new A.a3(!1,null)
B.Il=new A.a3(!1,!0)
B.fs=new A.c3(16,"scrollUp")
B.fu=new A.c3(32,"scrollDown")
B.Im=new A.a3(B.fs,B.fu)
B.In=new A.a3("Hasn't the whole world been mapped already?","No. There is a difference between remote imagery of an area from satellites and the kinds of maps we are making. The level of detail combining physical geography with cultural-historical information in the community is unique and critical to our process.")
B.Io=new A.a3("Who and what legal authority authorizes this project?","This initiative proceeds only with community consent and institutional coordination. During a reconnaissance expedition in Summer 2025, the research team met with the Indigenous community of San Juan Peque\xf1\xed, participated in a formal Local Congress, and received written approval.\n\nThis authorization aligns with Panama's 2008 Law 72 governing Collective Indigenous Lands. The project continues only through collaborative agreement with community leadership.")
B.Ip=new A.a3(B.fu,B.fs)
B.Iq=new A.a3("Community leadership engagement","Participaci\xf3n del liderazgo comunitario")
B.Ir=new A.a3("Indigenous cultural performance","Presentaci\xf3n cultural ind\xedgena")
B.Is=new A.a3(!0,!1)
B.It=new A.a3(!0,!0)
B.Iu=new A.a3("How does mapping help protect an area like this?","National park boundaries alone do not ensure protection. Effective stewardship requires understanding the ecological and social processes occurring within those boundaries.\n\nParticipatory research mapping translates Indigenous geographic knowledge into structured formats that can support zoning, monitoring, and long-term governance planning. At a fundamental level, it is difficult to protect what is not clearly understood.")
